VALUES
  ('optician-moex-02789', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '患者在近點聚合評估（near point of convergence, NPC）時所得到的結果是6公分／8公分。這6公分／8公分 所代表的意思為何？', '["6公分為模糊點（blur point），8公分為回復點（recovery point）", "6公分為模糊點（blur point），8公分為清晰點（clear point）", "6公分為破裂點（break point），8公分為清晰點（clear point）", "6公分為破裂點（break point），8公分為回復點（recovery point）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02790', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在進行魏氏四點（Worth four-dot）平面融像能力檢測（flat fusional test），右眼戴紅色鏡片，左眼戴綠色 鏡片，患者告知他看到五個點，兩個紅點在患者的左側，三個綠點在右側，則此患者最可能患有：', '["左眼抑制現象（suppression）", "右眼抑制現象", "外斜現象，交叉性複視（exo deviation, cross diplopia）", "內斜現象，非交叉性複視（eso deviation, un-cross diplopia）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02791', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在進行遮蓋測試時，發現患者有內斜視（esotropia），若要中和患者的內斜視，則稜鏡基底應該朝那個方 向？', '["基底朝內", "基底朝外", "基底朝上", "基底朝下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02792', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在進行遮蓋測試時，患者注視著你指定的視標。若患者左眼被遮蓋時，右眼保持不動，而你遮蓋右眼時， 左眼移動了，此時你將遮眼棒從右眼拿開時，左眼又移回原先位置，而右眼也回歸對準視標，則此患者 最可能患有：', '["有隱斜位但無斜視（phoria only）", "交替性斜視（alternating tropia）", "右眼持續性斜視（right constant tropia）", "左眼持續性斜視（left constant tropia）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02793', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '要分辨視力品質不佳的原因為矯正度數不正確或與病理有關時，一般採用下列那一種測試？', '["視野測試", "針孔測試", "瞳孔反應測試", "眼外肌測試"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02794', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列關於針孔視力的敘述，何者正確？①使用針孔，視力一定會提升  ②使用針孔可以區分出弱視或單純屈', '["針孔視力是運用視網膜照度增大的原理來提升視力值", "使用針孔後，視網膜上的模糊斑會縮小", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02795', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有一受測者的VA值，用分數記錄為6/30，則下列敘述何者錯誤？', '["此受測者的VA值，用最小分辨角（MAR）來表示為1分角", "此受測者的VA值，用小數記錄為0.2", "該視標測試標準距離為6公尺", "正常人在距離30公尺能看清的字，此受測者需在6公尺的距離才能看到"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02796', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者在5公尺檢查距離，無法看到0.1之視標，須往前走至視標前2公尺才可看清楚，則此人的視力為何？', '["0.04", "0.05", "0.02", "0.01"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02797', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '若注視右下方時，負責主要作用的眼外肌是下列那兩條？', '["右上斜肌，左下直肌", "右下直肌，左上斜肌", "右下斜肌，左下直肌", "右上直肌，左上斜肌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02798', 'optician', 'optician-moex-106-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在67公分處使用平行光進行靜態視網膜檢影（static retinoscopy）並中和後，若向前移動至50公分工作 距離處，患者的視網膜檢影反射光會變成下列何者？', '["無反射光", "順動反射光", "逆動反射光", "中和反射光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "6910876e629c", "answer_pdf_sha1": "a39ff037594a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
